const fs = require('fs'); // imports fs module (native) from Node.js
const Coupon = require('./coupon'); // imports our 'Coupon' module

const path = './coupons/' + 'MY_COUPON_CODE_1234.json'; // set the filename


function add(coupon, quantity){
    const total_discount = coupon.getDiscount();
    
    const newCoupon = new Coupon(coupon); // clone the existing coupon and call it new one
    newCoupon.code = '';
    newCoupon.discount *= (1 - total_discount/quantity)

    return newCoupon;
}


fs.readFile(path, 'utf8', function(err, data){ // read the file that was written to
    if (!err){ // the first argument to err is error code and it is undefined
        const coupon = JSON.parse(data);
        console.log('Original Coupon:');
        console.log(coupon);
        
        const newCoupon = add(coupon, 2) // add 2 more discount
        console.log('\nNew Coupon:');
        console.log(newCoupon);
    } else {
        console.log("File does not exist.") // show the error if the file is not found
    }
});